{
    "level": "A2–B1",
    "intro": "In this topic you will learn to build <strong>subject questions</strong> — questions about the person or thing that <strong>does the action</strong>.",
    "rules": [
        {
            "label": "WHO / WHAT AS SUBJECT",
            "color": "emerald",
            "text": "When <strong>who</strong> or <strong>what</strong> is the subject, it stands in the subject position itself:",
            "example": "Who called you? / What happened?"
        },
        {
            "label": "NO DO / DOES / DID",
            "color": "blue",
            "text": "In a normal subject question, we <strong>do not add do / does / did</strong>.",
            "example": "Who lives here? not Who does live here?"
        },
        {
            "label": "OBJECT QUESTION = DIFFERENT",
            "color": "amber",
            "text": "If the question word is not the subject, it is an <strong>object question</strong> and it often needs an auxiliary.",
            "example": "Who called you? vs Who did you call?"
        }
    ]
}

{
    "title": "1. Basic pattern",
    "intro": "Compare subject questions and object questions.",
    "items": [
        {
            "label": "Subject question",
            "title": "Who called you?",
            "subtitle": "who = subject, no did"
        },
        {
            "label": "Object question",
            "title": "Who did you call?",
            "subtitle": "who = object, did is needed"
        },
        {
            "label": "Main formula",
            "title": "Who / What + verb + ...?",
            "subtitle": "Who wants coffee? / What caused the problem?"
        },
        {
            "label": "Key rule",
            "title": "no inversion, no do-support",
            "subtitle": "the order is closer to a statement"
        }
    ]
}

{
    "title": "2. How subject questions work",
    "sections": [
        {
            "label": "Who as the subject",
            "color": "emerald",
            "description": "When we do not know <strong>which person</strong> did the action, we use <strong>who</strong> as the subject.",
            "examples": [
                {
                    "en": "Who called you last night?",
                    "ua": "Who called you last night?"
                },
                {
                    "en": "Who lives in that house?",
                    "ua": "Who lives in that house?"
                },
                {
                    "en": "Who wants some tea?",
                    "ua": "Who wants some tea?"
                }
            ]
        },
        {
            "label": "What as the subject",
            "color": "blue",
            "description": "When we ask about the <strong>thing, event, or cause</strong> that is the subject, we use <strong>what</strong>.",
            "examples": [
                {
                    "en": "What happened?",
                    "ua": "What happened?"
                },
                {
                    "en": "What made you laugh?",
                    "ua": "What made you laugh?"
                },
                {
                    "en": "What caused the delay?",
                    "ua": "What caused the delay?"
                }
            ]
        },
        {
            "label": "Contrast with object questions",
            "color": "amber",
            "description": "Ask yourself: <strong>who does the action</strong> or <strong>who receives the action</strong>? That decides the structure.",
            "examples": [
                {
                    "en": "Who called you?",
                    "ua": "Who called you?"
                },
                {
                    "en": "Who did you call?",
                    "ua": "Who did you call?"
                },
                {
                    "en": "What broke the window?",
                    "ua": "What broke the window?"
                },
                {
                    "en": "What did you break?",
                    "ua": "What did you break?"
                }
            ],
            "note": "If the wh-word is the subject, do not add do / does / did."
        }
    ]
}

{
    "title": "3. Common mistakes",
    "items": [
        {
            "label": "Mistake 1",
            "color": "rose",
            "title": "Adding do / does / did to a subject question.",
            "wrong": "Who did call you?",
            "right": "✅ <span class=\"font-mono\">Who called you?</span>"
        },
        {
            "label": "Mistake 2",
            "color": "amber",
            "title": "Mixing up a subject question and an object question.",
            "wrong": "Who called you? = the person you called",
            "right": "✅ <span class=\"font-mono\">Who did you call?</span> = the person you called"
        },
        {
            "label": "Mistake 3",
            "color": "sky",
            "title": "Using inversion after what.",
            "wrong": "What did happen?",
            "right": "✅ <span class=\"font-mono\">What happened?</span>"
        }
    ]
}

